"use client"

import { type VariantProps } from "class-variance-authority"
import { FriendButtonUI, friendButtonVariants } from "./ui"
import {
  useFriend,
  type FriendResult,
  type FriendshipStatus,
  type UseFriendReturn,
  type UseFriendOptions,
} from "./use-friend"

// ---------------------------------------------------------------------------
// Re-exports
// ---------------------------------------------------------------------------

export {
  FriendButtonUI,
  friendButtonVariants,
  type FriendButtonUIProps,
} from "./ui"
export {
  useFriend,
  type FriendResult,
  type FriendshipStatus,
  type UseFriendReturn,
  type UseFriendOptions,
} from "./use-friend"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface FriendButtonProps
  extends VariantProps<typeof friendButtonVariants> {
  /** Additional CSS classes */
  className?: string
  /** Identity key of the other user */
  identityKey: string
  /** Current friendship status */
  status: FriendshipStatus
  /** Called to send a friend request (creates a BSocial follow) */
  onAddFriend: (identityKey: string) => Promise<FriendResult>
  /** Called to accept an incoming request (creates a mutual follow + derives shared key) */
  onAccept?: (identityKey: string) => Promise<FriendResult>
  /** Called to decline an incoming request */
  onDecline?: (identityKey: string) => Promise<FriendResult>
  /** Called to remove an existing friend */
  onRemove?: (identityKey: string) => Promise<FriendResult>
  /** Called after any successful action with the new status */
  onStatusChange?: (newStatus: FriendshipStatus, result: FriendResult) => void
  /** Called on error */
  onError?: (error: Error) => void
  /** Disable the button */
  disabled?: boolean
}

// ---------------------------------------------------------------------------
// Composed component
// ---------------------------------------------------------------------------

/**
 * A friend request button with four states: Add Friend, Pending (sent),
 * Accept/Decline (received), and Friends.
 *
 * Uses BSocial follow protocol for friend requests. When both users follow
 * each other, they become "friends" and can derive shared encryption keys
 * via `getFriendPublicKey()` from `@1sat/actions`.
 *
 * @example
 * ```tsx
 * import { FriendButton } from "@/components/blocks/friend-button"
 *
 * <FriendButton
 *   identityKey="02abc..."
 *   status="none"
 *   onAddFriend={async (id) => {
 *     // create BSocial follow tx
 *     return { txid: "abc123..." }
 *   }}
 *   onAccept={async (id) => {
 *     // create mutual follow + derive shared key
 *     return { txid: "def456...", friendPublicKey: "03xyz..." }
 *   }}
 * />
 * ```
 */
export function FriendButton({
  variant = "default",
  className,
  identityKey,
  status,
  onAddFriend,
  onAccept,
  onDecline,
  onRemove,
  onStatusChange,
  onError,
  disabled = false,
}: FriendButtonProps) {
  const hook = useFriend({
    identityKey,
    status,
    onAddFriend,
    onAccept,
    onDecline,
    onRemove,
    onStatusChange,
    onError,
  })

  return (
    <FriendButtonUI
      variant={variant}
      className={className}
      identityKey={identityKey}
      currentStatus={hook.currentStatus}
      isLoading={hook.isLoading}
      loadingAction={hook.loadingAction}
      isHovering={hook.isHovering}
      onMouseEnter={() => hook.setIsHovering(true)}
      onMouseLeave={() => hook.setIsHovering(false)}
      onAdd={hook.handleAdd}
      onAccept={hook.handleAccept}
      onDecline={hook.handleDecline}
      onRemove={hook.handleRemove}
      hasAccept={hook.hasAccept}
      hasDecline={hook.hasDecline}
      hasRemove={hook.hasRemove}
      disabled={disabled}
    />
  )
}

"use client"

import { cva, type VariantProps } from "class-variance-authority"
import { cn } from "@/lib/utils"
import { Button } from "@/components/ui/button"
import { Check, Loader2, UserCheck, UserPlus, UserX, X } from "lucide-react"
import type { FriendshipStatus } from "./use-friend"

// ---------------------------------------------------------------------------
// Variant definitions
// ---------------------------------------------------------------------------

export const friendButtonVariants = cva(
  "inline-flex items-center justify-center gap-2 font-medium transition-all",
  {
    variants: {
      variant: {
        default: "rounded-md px-4 py-2 text-sm shadow-sm",
        compact: "rounded-md px-3 py-1.5 text-xs shadow-sm",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
)

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface FriendButtonUIProps
  extends VariantProps<typeof friendButtonVariants> {
  /** Additional CSS classes */
  className?: string
  /** Identity key of the other user (for aria-label) */
  identityKey: string
  /** Current friendship status */
  currentStatus: FriendshipStatus
  /** Whether an action is in progress */
  isLoading: boolean
  /** Which action is currently loading */
  loadingAction: string | null
  /** Whether the user is hovering (for friends state) */
  isHovering: boolean
  /** Handle mouse enter */
  onMouseEnter: () => void
  /** Handle mouse leave */
  onMouseLeave: () => void
  /** Handle add friend */
  onAdd: () => void
  /** Handle accept */
  onAccept: () => void
  /** Handle decline */
  onDecline: () => void
  /** Handle remove */
  onRemove: () => void
  /** Whether onAccept is available */
  hasAccept: boolean
  /** Whether onDecline is available */
  hasDecline: boolean
  /** Whether onRemove is available */
  hasRemove: boolean
  /** Disable the button */
  disabled?: boolean
}

// ---------------------------------------------------------------------------
// Component
// ---------------------------------------------------------------------------

export function FriendButtonUI({
  variant = "default",
  className,
  identityKey,
  currentStatus,
  isLoading,
  loadingAction,
  isHovering,
  onMouseEnter,
  onMouseLeave,
  onAdd,
  onAccept,
  onDecline,
  onRemove,
  hasAccept,
  hasDecline,
  hasRemove,
  disabled = false,
}: FriendButtonUIProps) {
  const buttonSize = variant === "compact" ? "sm" : "default" as const

  // --- None: "Add Friend" ---
  if (currentStatus === "none") {
    return (
      <Button
        size={buttonSize}
        className={cn(
          friendButtonVariants({ variant }),
          "bg-primary text-primary-foreground hover:bg-primary/90",
          className,
        )}
        onClick={onAdd}
        disabled={disabled || isLoading}
        aria-label={`Send friend request to ${identityKey}`}
        aria-busy={isLoading}
      >
        {isLoading ? (
          <>
            <Loader2 className="animate-spin" data-icon="inline-start" aria-hidden="true" />
            <span>Sending...</span>
          </>
        ) : (
          <>
            <UserPlus data-icon="inline-start" aria-hidden="true" />
            <span>Add Friend</span>
          </>
        )}
      </Button>
    )
  }

  // --- Pending Sent: "Pending" ---
  if (currentStatus === "pending-sent") {
    return (
      <Button
        variant="outline"
        size={buttonSize}
        className={cn(
          friendButtonVariants({ variant }),
          "bg-muted text-muted-foreground cursor-default",
          className,
        )}
        disabled
        aria-label="Friend request pending"
      >
        <Loader2 className="animate-spin opacity-50" data-icon="inline-start" aria-hidden="true" />
        <span>Pending</span>
      </Button>
    )
  }

  // --- Pending Received: "Accept" + "Decline" ---
  if (currentStatus === "pending-received") {
    return (
      <div className="inline-flex items-center gap-2">
        {hasAccept && (
          <Button
            size={buttonSize}
            className={cn("gap-2", className)}
            onClick={onAccept}
            disabled={disabled || isLoading}
            aria-label={`Accept friend request from ${identityKey}`}
            aria-busy={loadingAction === "accept"}
          >
            {loadingAction === "accept" ? (
              <>
                <Loader2 className="animate-spin" data-icon="inline-start" aria-hidden="true" />
                Accepting...
              </>
            ) : (
              <>
                <Check data-icon="inline-start" aria-hidden="true" />
                Accept
              </>
            )}
          </Button>
        )}

        {hasDecline && (
          <Button
            variant="outline"
            size={buttonSize}
            className="gap-2"
            onClick={onDecline}
            disabled={disabled || isLoading}
            aria-label={`Decline friend request from ${identityKey}`}
            aria-busy={loadingAction === "decline"}
          >
            {loadingAction === "decline" ? (
              <Loader2 className="animate-spin" data-icon="inline-start" aria-hidden="true" />
            ) : (
              <X data-icon="inline-start" aria-hidden="true" />
            )}
            Decline
          </Button>
        )}
      </div>
    )
  }

  // --- Friends: show "Friends" badge, with hover to "Remove" ---
  return (
    <Button
      variant="ghost"
      size={buttonSize}
      className={cn(
        friendButtonVariants({ variant }),
        !isHovering &&
          "border border-primary/20 bg-primary/5 text-primary",
        isHovering &&
          hasRemove &&
          "border border-destructive/30 bg-destructive/5 text-destructive hover:bg-destructive/10",
        isHovering && !hasRemove && "border border-primary/20 bg-primary/5 text-primary",
        className,
      )}
      onClick={hasRemove ? onRemove : undefined}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
      disabled={disabled || isLoading || !hasRemove}
      aria-label={
        isHovering && hasRemove
          ? `Remove friend ${identityKey}`
          : `Friends with ${identityKey}`
      }
    >
      {isLoading ? (
        <>
          <Loader2 className="animate-spin" data-icon="inline-start" aria-hidden="true" />
          <span>Removing...</span>
        </>
      ) : isHovering && hasRemove ? (
        <>
          <UserX data-icon="inline-start" aria-hidden="true" />
          <span>Remove</span>
        </>
      ) : (
        <>
          <UserCheck data-icon="inline-start" aria-hidden="true" />
          <span>Friends</span>
        </>
      )}
    </Button>
  )
}

import { useCallback, useState } from "react"

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

/**
 * The friendship state from the current user's perspective:
 * - `none` -- no relationship
 * - `pending-sent` -- current user sent a request (waiting for acceptance)
 * - `pending-received` -- another user sent a request (can accept or decline)
 * - `friends` -- mutual follow established
 */
export type FriendshipStatus =
  | "none"
  | "pending-sent"
  | "pending-received"
  | "friends"

export interface FriendResult {
  /** Transaction ID of the action */
  txid?: string
  /** Derived public key for encrypted messaging (returned on accept) */
  friendPublicKey?: string
  /** Raw transaction hex */
  rawtx?: string
  /** Error message if the action failed */
  error?: string
}

export interface UseFriendOptions {
  /** Identity key of the other user */
  identityKey: string
  /** Current friendship status */
  status: FriendshipStatus
  /** Called to send a friend request (creates a BSocial follow) */
  onAddFriend: (identityKey: string) => Promise<FriendResult>
  /** Called to accept an incoming request (creates a mutual follow + derives shared key) */
  onAccept?: (identityKey: string) => Promise<FriendResult>
  /** Called to decline an incoming request */
  onDecline?: (identityKey: string) => Promise<FriendResult>
  /** Called to remove an existing friend */
  onRemove?: (identityKey: string) => Promise<FriendResult>
  /** Called after any successful action with the new status */
  onStatusChange?: (newStatus: FriendshipStatus, result: FriendResult) => void
  /** Called on error */
  onError?: (error: Error) => void
}

export interface UseFriendReturn {
  /** Current friendship status */
  currentStatus: FriendshipStatus
  /** Whether an action is in progress */
  isLoading: boolean
  /** Which action is currently loading */
  loadingAction: string | null
  /** Whether the user is hovering (for friends state) */
  isHovering: boolean
  /** Set the hovering state */
  setIsHovering: (hovering: boolean) => void
  /** Execute an action (add, accept, decline, remove) */
  executeAction: (
    action: (id: string) => Promise<FriendResult>,
    actionName: string,
    newStatus: FriendshipStatus,
  ) => Promise<void>
  /** Whether onAccept is available */
  hasAccept: boolean
  /** Whether onDecline is available */
  hasDecline: boolean
  /** Whether onRemove is available */
  hasRemove: boolean
  /** Convenience handlers */
  handleAdd: () => void
  handleAccept: () => void
  handleDecline: () => void
  handleRemove: () => void
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useFriend({
  identityKey,
  status,
  onAddFriend,
  onAccept,
  onDecline,
  onRemove,
  onStatusChange,
  onError,
}: UseFriendOptions): UseFriendReturn {
  const [currentStatus, setCurrentStatus] = useState<FriendshipStatus>(status)
  const [isLoading, setIsLoading] = useState(false)
  const [loadingAction, setLoadingAction] = useState<string | null>(null)
  const [isHovering, setIsHovering] = useState(false)

  const executeAction = useCallback(
    async (
      action: (id: string) => Promise<FriendResult>,
      actionName: string,
      newStatus: FriendshipStatus,
    ) => {
      setIsLoading(true)
      setLoadingAction(actionName)

      try {
        const result = await action(identityKey)

        if (result.error) {
          onError?.(new Error(result.error))
        } else {
          setCurrentStatus(newStatus)
          onStatusChange?.(newStatus, result)
        }
      } catch (err) {
        const error = err instanceof Error ? err : new Error(`Failed to ${actionName}`)
        onError?.(error)
      } finally {
        setIsLoading(false)
        setLoadingAction(null)
      }
    },
    [identityKey, onStatusChange, onError],
  )

  const handleAdd = useCallback(() => {
    void executeAction(onAddFriend, "add", "pending-sent")
  }, [executeAction, onAddFriend])

  const handleAccept = useCallback(() => {
    if (onAccept) {
      void executeAction(onAccept, "accept", "friends")
    }
  }, [executeAction, onAccept])

  const handleDecline = useCallback(() => {
    if (onDecline) {
      void executeAction(onDecline, "decline", "none")
    }
  }, [executeAction, onDecline])

  const handleRemove = useCallback(() => {
    if (onRemove) {
      void executeAction(onRemove, "remove", "none")
    }
  }, [executeAction, onRemove])

  return {
    currentStatus,
    isLoading,
    loadingAction,
    isHovering,
    setIsHovering,
    executeAction,
    hasAccept: !!onAccept,
    hasDecline: !!onDecline,
    hasRemove: !!onRemove,
    handleAdd,
    handleAccept,
    handleDecline,
    handleRemove,
  }
}
